use crate::ai::runtime;
use crate::ai::types::*;
use serde::{Deserialize, Serialize};
use tauri::AppHandle;
use std::sync::Mutex;
use std::path::Path;

const SESSION_FILE: &str = ".app_session.json";

/// Conversation state held in Tauri's managed state
pub struct ConversationState {
    pub messages: Mutex<Vec<Message>>,
    pub system_prompt: Mutex<String>,
    pub workspace_path: Mutex<String>,
    pub provider: Mutex<String>,
    pub model: Mutex<String>,
    /// Lesson brief generated by Prep Phase (multi-agent)
    pub lesson_brief: Mutex<Option<String>>,
    /// Teaching-specific system prompt (loaded from split config files)
    pub teaching_prompt: Mutex<String>,
    /// Practice-specific system prompt
    pub practice_prompt: Mutex<String>,
    /// Meta Prompt system prompt (for workspace generation flow)
    pub meta_prompt_prompt: Mutex<String>,
}

impl Default for ConversationState {
    fn default() -> Self {
        Self {
            messages: Mutex::new(Vec::new()),
            system_prompt: Mutex::new(String::new()),
            workspace_path: Mutex::new(String::new()),
            provider: Mutex::new("anthropic".to_string()),
            model: Mutex::new(String::new()),
            lesson_brief: Mutex::new(None),
            teaching_prompt: Mutex::new(String::new()),
            practice_prompt: Mutex::new(String::new()),
            meta_prompt_prompt: Mutex::new(String::new()),
        }
    }
}

/// Serializable session state for persistence
#[derive(Serialize, Deserialize)]
struct SavedSession {
    messages: Vec<Message>,
    system_prompt: String,
    provider: String,
    #[serde(default)]
    model: String,
}

fn save_session_to_file(workspace_path: &str, session: &SavedSession) -> Result<(), String> {
    if workspace_path.is_empty() {
        return Ok(());
    }
    let path = Path::new(workspace_path).join(SESSION_FILE);
    let json = serde_json::to_string(session).map_err(|e| format!("Serialize error: {}", e))?;
    std::fs::write(&path, json).map_err(|e| format!("Write error: {}", e))?;
    Ok(())
}

fn load_session_from_file(workspace_path: &str) -> Option<SavedSession> {
    let path = Path::new(workspace_path).join(SESSION_FILE);
    let json = std::fs::read_to_string(&path).ok()?;
    serde_json::from_str(&json).ok()
}

#[derive(Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct StartSessionPayload {
    pub workspace_path: String,
    pub system_prompt: String,
    #[serde(default = "default_provider")]
    pub provider: String,
    #[serde(default)]
    pub model: String,
}

fn default_provider() -> String {
    "anthropic".to_string()
}

#[derive(Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SendMessagePayload {
    pub text: String,
    pub api_key: String,
}

/// Start a new AI session — set system prompt, workspace, and provider; clear history
#[tauri::command]
pub fn start_ai_session(
    state: tauri::State<'_, ConversationState>,
    payload: StartSessionPayload,
) -> Result<(), String> {
    let mut messages = state.messages.lock().map_err(|e| e.to_string())?;
    let mut system_prompt = state.system_prompt.lock().map_err(|e| e.to_string())?;
    let mut workspace_path = state.workspace_path.lock().map_err(|e| e.to_string())?;
    let mut provider = state.provider.lock().map_err(|e| e.to_string())?;
    let mut model = state.model.lock().map_err(|e| e.to_string())?;

    messages.clear();
    *system_prompt = payload.system_prompt;
    *workspace_path = payload.workspace_path;
    *provider = payload.provider;
    *model = payload.model;

    Ok(())
}

/// Send a user message and run the agent loop.
/// The AI response (including tool calls) is streamed via Tauri events.
#[tauri::command]
pub async fn send_chat_message(
    app: AppHandle,
    state: tauri::State<'_, ConversationState>,
    payload: SendMessagePayload,
) -> Result<(), String> {
    let system_prompt = state
        .system_prompt
        .lock()
        .map_err(|e| e.to_string())?
        .clone();
    let workspace_path = state
        .workspace_path
        .lock()
        .map_err(|e| e.to_string())?
        .clone();
    let provider = state
        .provider
        .lock()
        .map_err(|e| e.to_string())?
        .clone();
    let model = state.model.lock().map_err(|e| e.to_string())?.clone();

    // Add user message
    let user_msg = Message {
        role: "user".to_string(),
        content: vec![ContentBlock::Text {
            text: payload.text.clone(),
        }],
    };

    // Clone messages + add user message locally (don't mutate shared state yet)
    let current_messages = {
        let messages = state.messages.lock().map_err(|e| e.to_string())?;
        let mut msgs = messages.clone();
        msgs.push(user_msg);
        msgs
    };

    // Run agent loop (this may involve multiple API calls if tool_use)
    let result = runtime::run_agent_turn(
        &app,
        &payload.api_key,
        &provider,
        &model,
        &workspace_path,
        &system_prompt,
        current_messages,
    )
    .await;

    match result {
        Ok(updated_messages) => {
            // Update conversation state with full history
            let mut messages = state.messages.lock().map_err(|e| e.to_string())?;
            *messages = updated_messages;

            // Persist session to file (non-fatal if it fails)
            let _ = save_session_to_file(
                &workspace_path,
                &SavedSession {
                    messages: messages.clone(),
                    system_prompt: system_prompt.clone(),
                    provider: provider.clone(),
                    model: model.clone(),
                },
            );

            Ok(())
        }
        Err(e) => {
            // Emit error event so frontend can recover
            use tauri::Emitter;
            let _ = app.emit("agent-event", crate::ai::types::AgentEvent::Error {
                message: e.clone(),
            });
            let _ = app.emit("agent-event", crate::ai::types::AgentEvent::TurnComplete);
            Err(e)
        }
    }
}

/// Get current conversation history (for debugging / persistence)
#[tauri::command]
pub fn get_conversation_history(
    state: tauri::State<'_, ConversationState>,
) -> Result<Vec<Message>, String> {
    let messages = state.messages.lock().map_err(|e| e.to_string())?;
    Ok(messages.clone())
}

/// Check if a saved session exists for the given workspace
#[tauri::command]
pub fn has_saved_session(workspace_path: String) -> bool {
    let path = Path::new(&workspace_path).join(SESSION_FILE);
    path.exists()
}

/// Restore a saved session from the workspace file
#[tauri::command]
pub fn restore_ai_session(
    state: tauri::State<'_, ConversationState>,
    workspace_path: String,
) -> Result<usize, String> {
    let saved = load_session_from_file(&workspace_path)
        .ok_or("No saved session found")?;

    let mut messages = state.messages.lock().map_err(|e| e.to_string())?;
    let mut sp = state.system_prompt.lock().map_err(|e| e.to_string())?;
    let mut wp = state.workspace_path.lock().map_err(|e| e.to_string())?;
    let mut pv = state.provider.lock().map_err(|e| e.to_string())?;

    let count = saved.messages.len();
    *messages = saved.messages;
    *sp = saved.system_prompt;
    *wp = workspace_path;
    *pv = saved.provider;

    Ok(count)
}

/// Clear the saved session file for a workspace
#[tauri::command]
pub fn clear_saved_session(workspace_path: String) -> Result<(), String> {
    let path = Path::new(&workspace_path).join(SESSION_FILE);
    if path.exists() {
        std::fs::remove_file(&path).map_err(|e| format!("Delete error: {}", e))?;
    }
    Ok(())
}

