/// Generate structured review notes from the current conversation.
/// Returns the notes as a Markdown string.
#[tauri::command]
pub async fn generate_lesson_notes(
    state: tauri::State<'_, ConversationState>,
    payload: GenerateNotesPayload,
) -> Result<String, String> {
    let provider = state.provider.lock().map_err(|e| e.to_string())?.clone();
    let model = state.model.lock().map_err(|e| e.to_string())?.clone();
    let messages = state.messages.lock().map_err(|e| e.to_string())?.clone();

    if messages.is_empty() {
        return Err("没有对话记录可以生成笔记".to_string());
    }

    runtime::generate_notes(&payload.api_key, &provider, &model, &messages).await
}

/// Generate Anki flashcards from the current conversation.
/// Returns TSV string (front\tback\ttags per line).
#[tauri::command]
pub async fn generate_anki_cards(
    state: tauri::State<'_, ConversationState>,
    payload: GenerateNotesPayload,
) -> Result<String, String> {
    let provider = state.provider.lock().map_err(|e| e.to_string())?.clone();
    let model = state.model.lock().map_err(|e| e.to_string())?.clone();
    let messages = state.messages.lock().map_err(|e| e.to_string())?.clone();

    if messages.is_empty() {
        return Err("没有对话记录可以生成 Anki 卡片".to_string());
    }

    runtime::generate_anki_cards(&payload.api_key, &provider, &model, &messages).await
}

/// Generate a summary from conversation messages for the post-lesson agent
fn generate_conversation_summary(messages: &[Message]) -> String {
    let mut summary = String::from("=== 课堂对话记录 ===\n\n");
    for msg in messages {
        let role_label = match msg.role.as_str() {
            "user" => "学生",
            "assistant" => "老师(内部)",
            _ => &msg.role,
        };
        for block in &msg.content {
            match block {
                ContentBlock::Text { text } => {
                    if !text.trim().is_empty() {
                        summary.push_str(&format!("[{}] {}\n\n", role_label, text.chars().take(500).collect::<String>()));
                    }
                }
                ContentBlock::ToolUse { name, input, .. } => {
                    if name == "respond_to_student" {
                        if let Some(content) = input["content"].as_str() {
                            summary.push_str(&format!("[老师→学生] {}\n\n", content));
                        }
                    }
                }
                ContentBlock::ToolResult { content, .. } => {
                    // Skip tool results in summary
                    let _ = content;
                }
            }
        }
    }
    summary
}
